import React, { useState, useEffect, memo } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";

const HORA_CIERRE = 12; // 12:00

function Header() {
  const { user, logout }   = useAuth();
  const navigate           = useNavigate();
  const [ahora, setAhora]  = useState(new Date());
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const id = setInterval(() => setAhora(new Date()), 1000);
    return () => clearInterval(id);
  }, []);

  const hora          = ahora.getHours();
  const sistemaAbierto = hora < HORA_CIERRE;

  const horaFormateada = ahora.toLocaleTimeString("es-CL", {
    hour:   "2-digit",
    minute: "2-digit",
    second: "2-digit",
  });

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <header className="bg-white shadow-sm border-b border-gray-200 sticky top-0 z-30">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">

          {/* Logo + nombre */}
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 rounded-lg bg-brand-teal flex items-center justify-center text-white font-bold text-sm select-none">
              SC
            </div>
            <div className="hidden sm:block">
              <p className="font-semibold text-gray-800 leading-tight text-sm">SICOPS</p>
              <p className="text-xs text-gray-400">Control de Obras</p>
            </div>
          </div>

          {/* Centro: indicador sistema */}
          <div className={`hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium border
            ${sistemaAbierto
              ? "bg-green-50 border-green-200 text-green-700"
              : "bg-red-50 border-red-200 text-red-700"}`}>
            <span className={`w-2 h-2 rounded-full ${sistemaAbierto ? "bg-green-500 animate-pulse" : "bg-red-400"}`} />
            {sistemaAbierto
              ? `🟢 ABIERTO · Cierra a las ${HORA_CIERRE}:00`
              : `🔴 CERRADO · Reabre a las 00:00`}
            <span className="ml-1 text-gray-400">·</span>
            <span className="font-mono">{horaFormateada}</span>
          </div>

          {/* Derecha: usuario + logout */}
          <div className="flex items-center gap-3">
            {/* Indicador móvil */}
            <span className={`md:hidden w-2.5 h-2.5 rounded-full ${sistemaAbierto ? "bg-green-500" : "bg-red-400"}`} />

            <div className="relative">
              <button
                onClick={() => setMenuOpen((v) => !v)}
                className="flex items-center gap-2 text-sm text-gray-700 hover:text-gray-900 focus:outline-none"
                aria-label="Menú de usuario"
              >
                <div className="w-8 h-8 rounded-full bg-primary-600 text-white flex items-center justify-center font-semibold text-xs">
                  {user?.nombre?.charAt(0) || "A"}
                </div>
                <span className="hidden sm:block max-w-[120px] truncate">{user?.nombre || user?.email}</span>
                <svg className="w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>

              {menuOpen && (
                <div className="absolute right-0 mt-2 w-52 bg-white rounded-xl shadow-lg border border-gray-100 py-1 animate-fade-in">
                  <div className="px-4 py-2 border-b border-gray-100">
                    <p className="text-xs text-gray-400">Sesión activa</p>
                    <p className="text-sm font-medium text-gray-700 truncate">{user?.email}</p>
                  </div>
                  <button
                    onClick={() => { setMenuOpen(false); navigate("/dashboard"); }}
                    className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50"
                  >
                    Dashboard
                  </button>
                  <button
                    onClick={() => { setMenuOpen(false); navigate("/obras"); }}
                    className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50"
                  >
                    Listado de obras
                  </button>
                  <button
                    onClick={() => { setMenuOpen(false); navigate("/historico"); }}
                    className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50"
                  >
                    Histórico
                  </button>
                  <div className="border-t border-gray-100 mt-1" />
                  <button
                    onClick={handleLogout}
                    className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50"
                  >
                    Cerrar sesión
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Overlay para cerrar menú */}
      {menuOpen && (
        <div className="fixed inset-0 z-[-1]" onClick={() => setMenuOpen(false)} />
      )}
    </header>
  );
}

export default memo(Header);
